    43→  async createAccount(network: SupportedNetworks): Promise<INetworkAccount> {
    44→    switch (network) {
    45→      case SupportedNetworks.TRON:
    46→        return this.tronNetworkService.createAccount();
    47→      case SupportedNetworks.ETHEREUM:
    48→        return this.ethereumNetworkService.createAccount();
