    58→  /**
    59→   * Gets the current balance of a currency at the specified address
    60→   * @param network The network to check
    61→   * @param address The address to check
    62→   * @param contractAddress The token contract address (null for native currency)
    63→   * @returns Current balance as a string
    64→   */
    65→  async getBalanceByAddress(
    66→    network: SupportedNetworks,
    67→    address: string,
    68→    contractAddress: string | null,
    69→  ): Promise<{ found: boolean; amount: string }> {
    70→    try {
    71→      let balance: string;
    72→
    73→      if (contractAddress === null) {
    74→        // Base currency (TRX, ETH, etc.)
    75→        switch (network) {
    76→          case SupportedNetworks.TRON:
    77→            balance = await this.tronNetworkService.getTrxBalance(address);
    78→            break;
    79→          case SupportedNetworks.ETHEREUM:
    80→            balance = await this.ethereumNetworkService.getBalance(address);
    81→            break;
    82→          case SupportedNetworks.BNB:
    83→            balance = await this.bnbNetworkService.getBalance(address);
    84→            break;
    85→          case SupportedNetworks.SOLANA:
    86→            throw new BadRequestException(
    87→              'Solana network is not supported yet',
    88→            );
    89→          default:
    90→            throw new BadRequestException('Unsupported network');
    91→        }
    92→      } else {
    93→        // Token currency - find currency by contract address
    94→        const currencies = await this.currencyService.getCurrencies({});
    95→        const tokenCurrency = currencies.find(
    96→          (c) => c.contractAddress === contractAddress && c.network === network,
    97→        );
    98→
    99→        if (!tokenCurrency) {
   100→          throw new BadRequestException(
   101→            `Currency not found for contract address: ${contractAddress}`,
   102→          );
   103→        }
   104→
   105→        switch (network) {
   106→          case SupportedNetworks.TRON:
   107→            balance = await this.tronNetworkService.getTokenBalance(
   108→              address,
   109→              tokenCurrency.code,
   110→            );
   111→            break;
   112→          case SupportedNetworks.ETHEREUM:
   113→            balance = await this.ethereumNetworkService.getTokenBalance(
   114→              address,
   115→              contractAddress,
   116→              tokenCurrency.decimalPlaces,
   117→            );
   118→            break;
   119→          case SupportedNetworks.BNB:
   120→            balance = await this.bnbNetworkService.getTokenBalance(
   121→              address,
   122→              contractAddress,
   123→              tokenCurrency.decimalPlaces,
   124→            );
   125→            break;
   126→          case SupportedNetworks.SOLANA:
   127→            throw new BadRequestException(
   128→              'Solana network is not supported yet',
   129→            );
   130→          default:
   131→            throw new BadRequestException('Unsupported network');
   132→        }
   133→      }
   134→
   135→      const amount = parseFloat(balance);
   136→      return {
   137→        found: amount > 0,
   138→        amount: balance,
   139→      };
   140→    } catch (error) {
   141→      this.logger.error({ error, message: 'Failed to get balance by address' });
   142→      return { found: false, amount: '0' };
   143→    }
   144→  }
