   146→  /**
   147→   * Sweeps funds from a one-time wallet to a destination address
   148→   * @param network The network to use
   149→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
   150→   * @param currencyCode Currency code (e.g., 'USDT', 'TRX', 'ETH')
   151→   * @param destinationAddress Address to sweep funds to
   152→   * @returns Transaction hash
   153→   */
   154→  async sweepFunds(
   155→    network: SupportedNetworks,
   156→    currencyCode: string,
   157→    options: Required<ISweepBaseParams>,
   158→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
   159→    const redisKey = `sweep:${options.indempotencyKey}`;
   160→    const indempotencyKeyCheck = await this.redis.getset(redisKey, '1');
   161→
   162→    if (indempotencyKeyCheck === '1') {
   163→      throw new BadRequestException('Sweep record already exists');
   164→    }
   165→
   166→    const existingSweepRecord = await this.db
   167→      .selectFrom('sweepRecord')
   168→      .selectAll()
   169→      .where('indempotencyKey', '=', options.indempotencyKey)
   170→      .executeTakeFirst();
   171→    if (existingSweepRecord) {
   172→      if (existingSweepRecord.status === 'completed') {
   173→        return {
   174→          swept: true,
   175→          transactionHash: existingSweepRecord.transactionHash,
   176→          amount: existingSweepRecord.amount,
   177→        };
   178→      }
   179→      if (existingSweepRecord.status === 'failed') {
   180→        this.notificationsService.sendNotification(
   181→          `Errow sweeping funds for indempotency key: ${options.indempotencyKey}`,
   182→        );
   183→        throw new BadRequestException('Sweep record failed');
   184→      }
   185→      this.notificationsService.sendNotification(
   186→        `Errow sweeping funds for indempotency key: ${options.indempotencyKey}`,
   187→      );
   188→      throw new BadRequestException('Sweep record already exists');
   189→    }
   190→    console.log({ currencyCode, network, options });
   191→    // Look up currency to determine if it's a base currency (contractAddress === null) or token
   192→    const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
   193→      currencyCode,
   194→      network,
   195→    );
   196→
   197→    if (!currency) {
   198→      throw new BadRequestException(
   199→        `Currency ${currencyCode} not found on ${network}`,
   200→      );
   201→    }
   202→
   203→    let transactionHash: string | undefined;
   204→    let amount: string | undefined;
   205→    let swept = false;
   206→
   207→    const sweepRecord = await this.db
   208→      .insertInto('sweepRecord')
   209→      .returning(['id'])
   210→      .values({
   211→        currencyId: currency.id,
   212→        fromAddress: options.fromAddress,
   213→        toAddress: options.toAddress,
   214→        amount: options.amount,
   215→        status: 'pending',
   216→        errorMessage: null,
   217→        indempotencyKey: options.indempotencyKey,
   218→      })
   219→      .executeTakeFirstOrThrow();
   220→
   221→    void this.redis.del(redisKey);
   222→
   223→    try {
   224→      // If contractAddress is null, it's a base currency (TRX, ETH, etc.)
   225→      if (currency.contractAddress === null) {
   226→        switch (network) {
   227→          case SupportedNetworks.TRON: {
   228→            const result = await this.tronNetworkService.sweepBase(options);
   229→            transactionHash = result.transactionHash;
   230→            amount = result.amount;
   231→            swept = true;
   232→            break;
   233→          }
   234→          case SupportedNetworks.ETHEREUM: {
   235→            const ethResult =
   236→              await this.ethereumNetworkService.sweepBase(options);
   237→            transactionHash = ethResult.transactionHash;
   238→            amount = ethResult.amount;
   239→            swept = true;
   240→            break;
   241→          }
   242→          case SupportedNetworks.BNB: {
   243→            const bnbResult = await this.bnbNetworkService.sweepBase(options);
   244→            transactionHash = bnbResult.transactionHash;
   245→            amount = bnbResult.amount;
   246→            swept = true;
   247→            break;
   248→          }
   249→          case SupportedNetworks.SOLANA:
   250→            throw new BadRequestException(
   251→              'Solana network is not supported yet',
   252→            );
   253→          default:
   254→            throw new BadRequestException('Unsupported network');
   255→        }
   256→      } else {
   257→        // Token currency - has contractAddress
   258→        switch (network) {
   259→          case SupportedNetworks.TRON: {
   260→            const tronResult = await this.tronNetworkService.sweepToken(
   261→              options.fromPrivateKey,
   262→              currencyCode,
   263→              options.toAddress,
   264→            );
   265→            transactionHash = tronResult.transactionHash;
   266→            amount = tronResult.amount;
   267→            swept = true;
   268→            break;
   269→          }
   270→          case SupportedNetworks.ETHEREUM: {
   271→            const ethResult = await this.ethereumNetworkService.sweepToken(
   272→              options.fromPrivateKey,
   273→              currencyCode,
   274→              options.toAddress,
   275→            );
   276→            transactionHash = ethResult.transactionHash;
   277→            amount = ethResult.amount;
   278→            swept = true;
   279→            break;
   280→          }
   281→          case SupportedNetworks.BNB: {
   282→            const bnbResult = await this.bnbNetworkService.sweepToken(
   283→              options.fromPrivateKey,
   284→              currencyCode,
   285→              options.toAddress,
   286→            );
   287→            transactionHash = bnbResult.transactionHash;
   288→            amount = bnbResult.amount;
   289→            swept = true;
   290→            break;
   291→          }
   292→          case SupportedNetworks.SOLANA:
   293→            throw new BadRequestException(
   294→              'Solana network is not supported yet',
   295→            );
   296→          default:
   297→            throw new BadRequestException('Unsupported network');
   298→        }
   299→      }
   300→
   301→      await this.db
   302→        .updateTable('sweepRecord')
   303→        .set({
   304→          status: 'completed',
   305→          transactionHash: transactionHash,
   306→        })
   307→        .where('id', '=', sweepRecord.id)
   308→        .execute();
   309→
   310→      return {
   311→        swept,
   312→        transactionHash,
   313→        amount,
   314→      };
   315→    } catch (error: unknown) {
   316→      await this.db
   317→        .updateTable('sweepRecord')
   318→        .set({
   319→          status: 'failed',
   320→          errorMessage:
   321→            error instanceof Error ? error.message : 'Unknown error',
   322→        })
   323→        .where('id', '=', sweepRecord.id)
   324→        .execute();
   325→      throw error;
   326→    }
   327→  }
