   329→  async getSweepRecord(
   330→    dateFrom: Date,
   331→    dateTo: Date,
   332→  ): Promise<Selectable<SweepRecordEntity>[]> {
   333→    return this.db
   334→      .selectFrom('sweepRecord')
   335→      .selectAll()
   336→      .where('createdAt', '>=', dateFrom)
   337→      .where('createdAt', '<=', dateTo)
