     1→import { CurrencyService } from '@modules/currency/services/currency.service';
     2→import { GoldrushService } from '@modules/goldrush/services/goldrush.service';
     3→import {
     4→  IGetTransactionHistoryParams,
     5→  INetworkTransaction,
     6→} from '@modules/networks/types/network.type';
     7→import { ethers } from 'ethers';
     8→import { Decimal } from 'decimal.js';
     9→import { INetworkAccount } from '../types/network-account.type';
    10→import { INetworkService, ISweepBaseParams } from '../types/network-service';
    11→import { SupportedNetworks } from '../types/network.type';
    12→
    13→const EVM_TOKEN_ABI = [
    14→  'function balanceOf(address owner) view returns (uint256)',
    15→  'function transfer(address to, uint256 amount) returns (bool)',
    16→];
    17→
    18→export abstract class BaseEvmNetworkService implements INetworkService {
    19→  abstract readonly networkName: SupportedNetworks;
    20→
    21→  constructor(
    22→    protected readonly provider: ethers.JsonRpcProvider,
    23→    protected readonly currencyService: CurrencyService,
    24→    protected readonly goldrushService: GoldrushService,
    25→  ) {}
    26→
    27→  async createAccount(): Promise<INetworkAccount> {
    28→    const wallet = ethers.Wallet.createRandom(this.provider);
    29→    return {
    30→      address: wallet.address,
    31→      privateKey: wallet.privateKey,
    32→      publicKey: wallet.signingKey.publicKey,
    33→      meta: JSON.parse(JSON.stringify(wallet)),
    34→    };
    35→  }
    36→
    37→  async getBalance(address: string): Promise<string> {
    38→    const balance = await this.provider.getBalance(address);
    39→    return ethers.formatEther(balance);
    40→  }
    41→
    42→  async getTokenBalance(
    43→    address: string,
    44→    contractAddress: string,
    45→    decimals: number,
    46→  ): Promise<string> {
    47→    const contract = new ethers.Contract(
    48→      contractAddress,
    49→      EVM_TOKEN_ABI,
    50→      this.provider,
    51→    );
    52→    const balance = await contract.balanceOf(address);
    53→    return ethers.formatUnits(balance, decimals);
    54→  }
    55→
    56→  async sweepToken(
    57→    oneTimeWalletPrivateKey: string,
    58→    currencyCode: string,
    59→    destinationAddress: string,
    60→  ): Promise<{ transactionHash: string; amount: string }> {
    61→    try {
    62→      const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
    63→        currencyCode,
    64→        this.networkName,
    65→      );
    66→
    67→      if (!currency || !currency.contractAddress) {
    68→        throw new Error(
    69→          `Currency ${currencyCode} not found or missing contract address`,
    70→        );
    71→      }
    72→
    73→      const wallet = new ethers.Wallet(oneTimeWalletPrivateKey, this.provider);
    74→      const contract = new ethers.Contract(
    75→        currency.contractAddress,
    76→        EVM_TOKEN_ABI,
    77→        wallet,
    78→      );
    79→      const balance = await contract.balanceOf(wallet.address);
    80→
    81→      if (balance === 0n) {
    82→        throw new Error('No tokens to sweep');
    83→      }
    84→
    85→      const tx = await contract.transfer(destinationAddress, balance);
    86→      const receipt = await tx.wait();
    87→
    88→      return { amount: balance.toString(), transactionHash: receipt.hash };
    89→    } catch (error) {
    90→      const errorMessage =
    91→        error instanceof Error ? error.message : String(error);
    92→      throw new Error(`Failed to sweep token: ${errorMessage}`);
    93→    }
    94→  }
    95→
    96→  async sweepBase(
    97→    params: ISweepBaseParams,
    98→  ): Promise<{ transactionHash: string; amount: string }> {
    99→    try {
   100→      const wallet = new ethers.Wallet(params.fromPrivateKey, this.provider);
   101→      const balance = await this.provider.getBalance(wallet.address);
   102→
   103→      if (balance === 0n) {
   104→        throw new Error('No native currency to sweep');
   105→      }
   106→
   107→      const gasPrice = await this.provider.getFeeData();
   108→      const estimatedGas = 21000n;
   109→      const gasCost = (gasPrice.gasPrice || 0n) * estimatedGas;
   110→      const amountToSend = balance > gasCost ? balance - gasCost : 0n;
   111→
   112→      if (amountToSend === 0n) {
   113→        throw new Error('Insufficient balance after gas deduction');
   114→      }
   115→
   116→      const sendAmount = params.amount
   117→        ? new Decimal(params.amount).mul('1000000000000000000')
   118→        : new Decimal(amountToSend.toString());
   119→
   120→      const tx = await wallet.sendTransaction({
   121→        to: params.toAddress,
   122→        value: BigInt(sendAmount.toString()),
   123→        gasLimit: estimatedGas,
   124→      });
   125→
   126→      const receipt = await tx.wait(2);
   127→
   128→      return { transactionHash: receipt.hash, amount: sendAmount.toString() };
   129→    } catch (error) {
   130→      const errorMessage =
   131→        error instanceof Error ? error.message : String(error);
   132→      throw new Error(`Failed to sweep base currency: ${errorMessage}`);
   133→    }
   134→  }
