import { CurrencyService } from '@modules/currency/services/currency.service';
import { Inject, Injectable } from '@nestjs/common';
import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
import { Db } from '@shared/database/types';
import { ethers } from 'ethers';
import { INetworkAccount } from '../../types/network-account.type';
import { INetworkService, ISweepBaseParams } from '../../types/network-service';
import { SupportedNetworks } from '../../types/network.type';
import { Decimal } from 'decimal.js';
import {
  IGetTransactionHistoryParams,
  INetworkTransaction,
} from '@modules/networks/types/network.type';
import { GoldrushService } from '@modules/goldrush/services/goldrush.service';
import { networksConfigs } from '@configs/networks.configs';
import { ConfigType } from '@nestjs/config';

@Injectable()
export class BnbNetworkService implements INetworkService {
  constructor(
    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    private readonly currencyService: CurrencyService,
    private readonly goldrushService: GoldrushService,
    @Inject(networksConfigs.KEY)
    private readonly networksConf: ConfigType<typeof networksConfigs>,
  ) {
    this.provider = new ethers.JsonRpcProvider(this.networksConf.bnb.rpcUrl);
  }
  private provider: ethers.JsonRpcProvider;
  readonly networkName = SupportedNetworks.BNB;

  async createAccount(): Promise<INetworkAccount> {
    const wallet = ethers.Wallet.createRandom(this.provider);
    const publicKey = wallet.signingKey.publicKey;

    return {
      address: wallet.address,
      privateKey: wallet.privateKey,
      publicKey: publicKey,
      meta: JSON.parse(JSON.stringify(wallet)),
    };
  }

  async getBalance(address: string): Promise<string> {
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }

  async getTokenBalance(
    address: string,
    contractAddress: string,
    decimals: number,
  ): Promise<string> {
    const erc20Abi = [
      'function balanceOf(address owner) view returns (uint256)',
    ];

    const contract = new ethers.Contract(
      contractAddress,
      erc20Abi,
      this.provider,
    );

    const balance = await contract.balanceOf(address);
    return ethers.formatUnits(balance, decimals);
  }

  async sweepToken(
    oneTimeWalletPrivateKey: string,
    currencyCode: string,
    destinationAddress: string,
  ): Promise<{ transactionHash: string; amount: string }> {
    try {
      const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
        currencyCode,
        SupportedNetworks.BNB,
      );

      if (!currency || !currency.contractAddress) {
        throw new Error(
          `Currency ${currencyCode} not found or missing contract address`,
        );
      }

      const contractAddress = currency.contractAddress;
      const wallet = new ethers.Wallet(oneTimeWalletPrivateKey, this.provider);

      const erc20Abi = [
        'function transfer(address to, uint256 amount) returns (bool)',
        'function balanceOf(address owner) view returns (uint256)',
      ];

      const contract = new ethers.Contract(contractAddress, erc20Abi, wallet);
      const balance = await contract.balanceOf(wallet.address);

      if (balance === 0n) {
        throw new Error('No tokens to sweep');
      }

      const tx = await contract.transfer(destinationAddress, balance);
      const receipt = await tx.wait();

      return { amount: balance.toString(), transactionHash: receipt.hash };
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : String(error);
      throw new Error(`Failed to sweep token: ${errorMessage}`);
    }
  }

  async sweepBase(
    params: ISweepBaseParams,
  ): Promise<{ transactionHash: string; amount: string }> {
    try {
      const wallet = new ethers.Wallet(params.fromPrivateKey, this.provider);
      const balance = await this.provider.getBalance(wallet.address);

      if (balance === 0n) {
        throw new Error('No BNB to sweep');
      }

      const gasPrice = await this.provider.getFeeData();
      const estimatedGas = 21000n;
      const gasCost = (gasPrice.gasPrice || 0n) * estimatedGas;

      const amountToSend = balance > gasCost ? balance - gasCost : 0n;

      if (amountToSend === 0n) {
        throw new Error('Insufficient balance after gas deduction');
      }

      const sendAmount = params.amount
        ? new Decimal(params.amount).mul('1000000000000000000')
        : new Decimal(amountToSend.toString());

      const tx = await wallet.sendTransaction({
        to: params.toAddress,
        value: BigInt(sendAmount.toString()),
        gasLimit: estimatedGas,
      });

      const receipt = await tx.wait(2);

      return { transactionHash: receipt.hash, amount: sendAmount.toString() };
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : String(error);
      throw new Error(`Failed to sweep BNB: ${errorMessage}`);
    }
  }

  async getTransactionHistory(
    options: IGetTransactionHistoryParams,
  ): Promise<INetworkTransaction[]> {
    if (options.contractAddress) {
      return this.goldrushService.getERC20TransfersToAdressFromDate({
        toAddress: options.address,
        network: SupportedNetworks.BNB,
        fromDate: new Date(options.sinceTimestamp),
        contractAddress: options.contractAddress,
      });
    }
    return this.goldrushService.getNativeTransfersToAdressFromDate({
      toAddress: options.address,
      network: SupportedNetworks.BNB,
      fromDate: new Date(options.sinceTimestamp),
      contractAddress: options.contractAddress,
    });
  }
}

